// RSS feeds to monitor
// Add/remove feeds as needed
const feeds = [
  { name: 'Hacker News (AI)', url: 'https://hnrss.org/newest?q=AI+LLM&count=20' },
  { name: 'The Gradient', url: 'https://thegradient.pub/rss/' },
  { name: 'Simon Willison', url: 'https://simonwillison.net/atom/everything/' },
  { name: 'Andrej Karpathy', url: 'https://karpathy.bearblog.dev/feed/' }
];

return feeds.map(f => ({ json: f }));

// Extract title, link, and pubDate from each RSS item
// Also filter to items from the last 24h
const items = $input.all();
const cutoff = Date.now() - 24 * 60 * 60 * 1000;
const results = [];

for (const item of items) {
  const html = item.json.items;
  if (!html) continue;

  const parseArr = Array.isArray(html) ? html : [html];
  for (const xmlStr of parseArr) {
    const titleMatch = xmlStr.match(/<title[^>]*><!\[CDATA\[([^\]]+)\]\]><\/title>/) ||
                       xmlStr.match(/<title[^>]*>([^<]+)<\/title>/);
    const linkMatch  = xmlStr.match(/<link[^>]*>([^<]+)<\/link>/) ||
                       xmlStr.match(/<guid[^>]*>([^<]+)<\/guid>/);
    const dateMatch  = xmlStr.match(/<pubDate[^>]*>([^<]+)<\/pubDate>/) ||
                       xmlStr.match(/<published[^>]*>([^<]+)<\/published>/);

    if (!titleMatch) continue;

    const pubDate = dateMatch ? new Date(dateMatch[1]).getTime() : Date.now();
    if (pubDate < cutoff) continue;

    results.push({
      json: {
        title: titleMatch[1].trim(),
        url: linkMatch ? linkMatch[1].trim() : '',
        pubDate: new Date(pubDate).toISOString()
      }
    });
  }
}

return results.slice(0, 15); // cap at 15 items per run

// Collect all summarized items and build the digest
const allItems = $input.all();
const originals = $('Extract & Filter').all();

let digest = `📰 *AI Digest — ${new Date().toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'short' })}*\n\n`;

for (let i = 0; i < allItems.length; i++) {
  const summary = allItems[i].json?.message?.content || allItems[i].json?.response || originals[i]?.json?.title || '?';
  const url = originals[i]?.json?.url || '';

  digest += `• ${summary.trim()}${url ? '\n  ' + url : ''}\n\n`;
}

return [{ json: { text: digest.trim() } }];
